+      Logger.debug(TAG,
+        `onPageHide state:${tmpData.avPlayer.state}, url:${tmpData.avPlayer.url}, curIndex:${this.curIndex}`)
+      if (tmpData.avPlayer.state === AVPlayerState.PLAYING) {
